package org.springframework.samples.petclinic.api.application;

import org.springframework.samples.petclinic.api.dto.ClinicSummary;
import org.springframework.stereotype.Service;
import reactor.core.publisher.Mono;

@Service
public class ClinicSummaryService {

    private final CustomersServiceClient customersServiceClient;
    private final VisitsServiceClient visitsServiceClient;
    private final org.springframework.samples.petclinic.vets.model.VetRepository vetRepository;

    public ClinicSummaryService(
            CustomersServiceClient customersServiceClient,
            VisitsServiceClient visitsServiceClient,
            org.springframework.samples.petclinic.vets.model.VetRepository vetRepository) {
        this.customersServiceClient = customersServiceClient;
        this.visitsServiceClient = visitsServiceClient;
        this.vetRepository = vetRepository;
    }

    public Mono<ClinicSummary> getClinicSummary() {
        Mono<Long> ownerCount = customersServiceClient.getAllOwnersCount();
        Mono<Long> petCount = customersServiceClient.getAllPetsCount();
        Mono<Long> visitCount = visitsServiceClient.getAllVisitsCount();
        Mono<Long> vetCount = Mono.fromCallable(vetRepository::count);

        return Mono.zip(ownerCount, petCount, visitCount, vetCount)
                .map(tuple -> new ClinicSummary(
                        tuple.getT1(),
                        tuple.getT2(),
                        tuple.getT3(),
                        tuple.getT4()
                ));
    }
}

