package org.springframework.samples.petclinic.genai;

import org.springframework.stereotype.Service;
import org.springframework.samples.petclinic.genai.dto.ArticleDto;

@Service
public class ArticleSlugValidationService {

    public void validateSlug(ArticleDto articleDto) {
        if (articleDto.slug() == null || articleDto.slug().trim().isEmpty()) {
            throw new IllegalArgumentException("Slug cannot be empty");
        }

        if (!articleDto.slug().matches("^[a-z0-9-]+$")) {
            throw new IllegalArgumentException("Slug can only contain lowercase letters, numbers, and hyphens");
        }

        if (articleDto.slug().length() > 100) {
            throw new IllegalArgumentException("Slug cannot exceed 100 characters");
        }
    }
}

