package org.springframework.samples.petclinic.customers.model;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.JoinColumn;
import jakarta.persistence.ManyToOne;
import jakarta.persistence.Table;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Size;
import java.util.Objects;

@Entity
@Table(name = "articles")
public class Article {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Integer id;

    @NotBlank
    @Size(max = 100)
    private String title;

    @NotBlank
    @Size(max = 255)
    @Column(name = "slug", unique = true)
    private String slug;

    @NotBlank
    @Size(max = 2000)
    private String content;

    @ManyToOne
    @JoinColumn(name = "owner_id")
    private Owner owner;

    public Article() {
    }

    public Article(String title, String slug, String content, Owner owner) {
        this.title = title;
        this.slug = slug;
        this.content = content;
        this.owner = owner;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getTitle() {
        return title;
    }

    public void setTitle(String title) {
        this.title = title;
    }

    public String getSlug() {
        return slug;
    }

    public void setSlug(String slug) {
        this.slug = slug;
    }

    public String getContent() {
        return content;
    }

    public void setContent(String content) {
        this.content = content;
    }

    public Owner getOwner() {
        return owner;
    }

    public void setOwner(Owner owner) {
        this.owner = owner;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Article article = (Article) o;
        return Objects.equals(id, article.id);
    }

    @Override
    public int hashCode() {
        return Objects.hash(id);
    }
}

package org.springframework.samples.petclinic.customers.model;

import org.springframework.data.jpa.repository.JpaRepository;
import java.util.Optional;

public interface ArticleRepository extends JpaRepository<Article, Integer> {
    boolean existsBySlug(String slug);
    Optional<Article> findBySlug(String slug);
}

package org.springframework.samples.petclinic.customers.service;

import org.springframework.samples.petclinic.customers.model.Article;
import org.springframework.samples.petclinic.customers.model.ArticleRepository;
import org.springframework.samples.petclinic.customers.model.Owner;
import org.springframework.samples.petclinic.customers.model.OwnerRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class ArticleService {

    private final ArticleRepository articleRepository;
    private final OwnerRepository ownerRepository;

    public ArticleService(ArticleRepository articleRepository, OwnerRepository ownerRepository) {
        this.articleRepository = articleRepository;
        this.ownerRepository = ownerRepository;
    }

    public Article createArticle(String title, String slug, String content, Integer ownerId) {
        validateSlug(slug);

        Owner owner = ownerRepository.findById(ownerId)
            .orElseThrow(() -> new IllegalArgumentException("Owner not found"));

        Article article = new Article(title, slug, content, owner);
        return articleRepository.save(article);
    }

    public Article updateArticle(Integer articleId, String title, String slug, String content) {
        validateSlug(slug);

        Article existingArticle = articleRepository.findById(articleId)
            .orElseThrow(() -> new IllegalArgumentException("Article not found"));

        existingArticle.setTitle(title);
        existingArticle.setSlug(slug);
        existingArticle.setContent(content);

        return articleRepository.save(existingArticle);
    }

    private void validateSlug(String slug) {
        if (slug == null || slug.trim().isEmpty()) {
            throw new IllegalArgumentException("Slug cannot be empty");
        }

        if (!slug.matches("^[a-z0-9-]+$")) {
            throw new IllegalArgumentException("Slug can only contain lowercase letters, numbers, and hyphens");
        }

        if (articleRepository.existsBySlug(slug)) {
            throw new IllegalArgumentException("Slug already exists");
        }
    }
}

package org.springframework.samples.petclinic.customers.web;

import org.springframework.samples.petclinic.customers.service.ArticleService;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;

@Controller
@RequestMapping("/articles")
public class ArticleController {

    private final ArticleService articleService;

    public ArticleController(ArticleService articleService) {
        this.articleService = articleService;
    }

    @GetMapping("/create")
    public String showCreateArticleForm(Model model) {
        model.addAttribute("article", new ArticleDto());
        return "articles/createOrUpdateArticleForm";
    }

    @PostMapping("/create")
    public String createArticle(ArticleDto articleDto) {
        articleService.createArticle(
            articleDto.getTitle(),
            articleDto.getSlug(),
            articleDto.getContent(),
            articleDto.getOwnerId()
        );
        return "redirect:/articles";
    }

    @GetMapping("/{articleId}/edit")
    public String showUpdateArticleForm(@PathVariable Integer articleId, Model model) {
        ArticleDto articleDto = new ArticleDto();
        model.addAttribute("article", articleDto);
        return "articles/createOrUpdateArticleForm";
    }

    @PostMapping("/{articleId}/edit")
    public String updateArticle(@PathVariable Integer articleId, ArticleDto articleDto) {
        articleService.updateArticle(
            articleId,
            articleDto.getTitle(),
            articleDto.getSlug(),
            articleDto.getContent()
        );
        return "redirect:/articles";
    }
}

