import org.springframework.samples.petclinic.customers.model.Article;
import org.springframework.samples.petclinic.customers.model.ArticleRepository;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.ResponseStatus;
import org.springframework.web.bind.annotation.RestControllerAdvice;
import org.springframework.web.server.ResponseStatusException;

@RestControllerAdvice
public class ArticleValidationExceptionHandler {

    @ExceptionHandler(InvalidSlugException.class)
    @ResponseStatus(HttpStatus.BAD_REQUEST)
    public String handleInvalidSlugException(InvalidSlugException ex) {
        return ex.getMessage();
    }
}

package org.springframework.samples.petclinic.customers.web;

import org.springframework.samples.petclinic.customers.model.Article;
import org.springframework.samples.petclinic.customers.model.ArticleRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.util.regex.Pattern;

@Service
@Transactional
public class ArticleSlugValidator {

    private static final Pattern SLUG_PATTERN = Pattern.compile("^[a-z0-9-]+$");
    private final ArticleRepository articleRepository;

    public ArticleSlugValidator(ArticleRepository articleRepository) {
        this.articleRepository = articleRepository;
    }

    public void validateAndPrepareSlug(Article article) {
        if (article == null || article.getSlug() == null) {
            throw new InvalidSlugException("Slug cannot be null");
        }

        String slug = article.getSlug().trim().toLowerCase();
        if (!SLUG_PATTERN.matcher(slug).matches()) {
            throw new InvalidSlugException("Slug must contain only lowercase letters, numbers, and hyphens");
        }

        if (slug.length() < 3 || slug.length() > 100) {
            throw new InvalidSlugException("Slug must be between 3 and 100 characters long");
        }

        if (article.getId() == null && articleRepository.existsBySlug(slug)) {
            throw new InvalidSlugException("Slug must be unique");
        }

        if (article.getId() != null && !articleRepository.findById(article.getId()).orElseThrow().getSlug().equals(slug)) {
            if (articleRepository.existsBySlug(slug)) {
                throw new InvalidSlugException("Slug must be unique");
            }
        }

        article.setSlug(slug);
    }
}

package org.springframework.samples.petclinic.customers.web;

public class InvalidSlugException extends RuntimeException {

    public InvalidSlugException(String message) {
        super(message);
    }
}

package org.springframework.samples.petclinic.customers.web;

import org.springframework.samples.petclinic.customers.model.Article;
import org.springframework.samples.petclinic.customers.model.ArticleRepository;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/articles")
public class ArticleResource {

    private final ArticleRepository articleRepository;
    private final ArticleSlugValidator articleSlugValidator;

    public ArticleResource(ArticleRepository articleRepository, ArticleSlugValidator articleSlugValidator) {
        this.articleRepository = articleRepository;
        this.articleSlugValidator = articleSlugValidator;
    }

    @PostMapping
    public Article createArticle(@RequestBody Article article) {
        articleSlugValidator.validateAndPrepareSlug(article);
        return articleRepository.save(article);
    }

    @PutMapping
    public Article updateArticle(@RequestBody Article article) {
        articleSlugValidator.validateAndPrepareSlug(article);
        return articleRepository.save(article);
    }
}

