package org.springframework.samples.petclinic.admin;

import org.springframework.boot.CommandLineRunner;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.samples.petclinic.customers.model.Owner;
import org.springframework.samples.petclinic.customers.model.OwnerRepository;
import org.springframework.samples.petclinic.customers.model.Pet;
import org.springframework.samples.petclinic.customers.model.PetType;
import org.springframework.samples.petclinic.customers.model.PetRepository;
import org.springframework.samples.petclinic.vets.model.Specialty;
import org.springframework.samples.petclinic.vets.model.Vet;
import org.springframework.samples.petclinic.vets.model.VetRepository;
import org.springframework.samples.petclinic.visits.model.Visit;
import org.springframework.samples.petclinic.visits.model.VisitRepository;

import java.text.ParseException;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

@SpringBootApplication
public class DataImportExportApplication {

    public static void main(String[] args) {
        SpringApplication.run(DataImportExportApplication.class, args);
    }

    @Bean
    public CommandLineRunner loadTestData(
            OwnerRepository ownerRepository,
            PetRepository petRepository,
            VetRepository vetRepository,
            VisitRepository visitRepository) {
        return args -> {
            if (args.length > 0 && "import".equals(args[0])) {
                importTestData(ownerRepository, petRepository, vetRepository, visitRepository);
            }
        };
    }

    private void importTestData(
            OwnerRepository ownerRepository,
            PetRepository petRepository,
            VetRepository vetRepository,
            VisitRepository visitRepository) throws ParseException {

        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd", Locale.ENGLISH);

        // Import Owners
        Owner owner1 = new Owner();
        owner1.setFirstName("George");
        owner1.setLastName("Franklin");
        owner1.setAddress("110 W. Liberty St.");
        owner1.setCity("Madison");
        owner1.setTelephone("6085551023");
        ownerRepository.save(owner1);

        Owner owner2 = new Owner();
        owner2.setFirstName("Betty");
        owner2.setLastName("Davis");
        owner2.setAddress("638 Cardinal Ave.");
        owner2.setCity("Sun Prairie");
        owner2.setTelephone("6085551749");
        ownerRepository.save(owner2);

        // Import PetTypes
        PetType dog = new PetType();
        dog.setName("dog");
        PetType savedDog = petRepository.savePetType(dog);

        PetType cat = new PetType();
        cat.setName("cat");
        PetType savedCat = petRepository.savePetType(cat);

        // Import Pets
        Pet pet1 = new Pet();
        pet1.setName("Leo");
        pet1.setBirthDate(dateFormat.parse("2010-09-07"));
        pet1.setType(savedDog);
        pet1.setOwner(owner1);
        petRepository.save(pet1);

        Pet pet2 = new Pet();
        pet2.setName("Basil");
        pet2.setBirthDate(dateFormat.parse("2012-08-06"));
        pet2.setType(savedCat);
        pet2.setOwner(owner2);
        petRepository.save(pet2);

        // Import Specialties
        Specialty radiology = new Specialty();
        radiology.setName("radiology");

        Specialty surgery = new Specialty();
        surgery.setName("surgery");

        Specialty dentistry = new Specialty();
        dentistry.setName("dentistry");

        // Import Vets
        Vet vet1 = new Vet();
        vet1.setFirstName("James");
        vet1.setLastName("Carter");
        vet1.getSpecialties().add(radiology);
        vetRepository.save(vet1);

        Vet vet2 = new Vet();
        vet2.setFirstName("Helen");
        vet2.setLastName("Leary");
        vet2.getSpecialties().add(surgery);
        vetRepository.save(vet2);

        // Import Visits
        Visit visit1 = new Visit();
        visit1.setPetId(pet1.getId());
        visit1.setDate(dateFormat.parse("2013-01-01"));
        visit1.setDescription("rabies shot");
        visitRepository.save(visit1);

        Visit visit2 = new Visit();
        visit2.setPetId(pet2.getId());
        visit2.setDate(dateFormat.parse("2013-01-02"));
        visit2.setDescription("neutered");
        visitRepository.save(visit2);
    }
}

