package org.springframework.samples.petclinic.genai;

import org.springframework.samples.petclinic.genai.dto.TestDataExport;
import org.springframework.stereotype.Service;

@Service
public class TestDataService {

    private final OwnerRepository ownerRepository;
    private final PetRepository petRepository;
    private final VetRepository vetRepository;
    private final VisitRepository visitRepository;

    public TestDataService(
            OwnerRepository ownerRepository,
            PetRepository petRepository,
            VetRepository vetRepository,
            VisitRepository visitRepository) {
        this.ownerRepository = ownerRepository;
        this.petRepository = petRepository;
        this.vetRepository = vetRepository;
        this.visitRepository = visitRepository;
    }

    public TestDataExport exportTestData() {
        return new TestDataExport(
            ownerRepository.findAll(),
            petRepository.findAll(),
            vetRepository.findAll(),
            visitRepository.findAll()
        );
    }

    public void importTestData(TestDataExport testData) {
        ownerRepository.saveAll(testData.owners());
        petRepository.saveAll(testData.pets());
        vetRepository.saveAll(testData.vets());
        visitRepository.saveAll(testData.visits());
    }
}

