package org.springframework.samples.petclinic.genai.web;

import org.springframework.http.ResponseEntity;
import org.springframework.samples.petclinic.genai.TestDataService;
import org.springframework.samples.petclinic.genai.dto.TestDataExport;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.samples.petclinic.customers.model.OwnerRepository;
import org.springframework.samples.petclinic.customers.model.PetRepository;
import org.springframework.samples.petclinic.vets.model.VetRepository;
import org.springframework.samples.petclinic.visits.model.VisitRepository;

@RestController
@RequestMapping("/api/test-data")
public class TestDataController {

    private final TestDataService testDataService;

    public TestDataController(TestDataService testDataService) {
        this.testDataService = testDataService;
    }

    @PostMapping("/import")
    public ResponseEntity<String> importTestData(@RequestBody TestDataExport testData) {
        try {
            testDataService.importTestData(testData);
            return ResponseEntity.ok("Test data imported successfully");
        } catch (Exception e) {
            return ResponseEntity.internalServerError().body("Error importing test data: " + e.getMessage());
        }
    }

    @GetMapping("/export")
    public ResponseEntity<TestDataExport> exportTestData() {
        try {
            TestDataExport testData = testDataService.exportTestData();
            return ResponseEntity.ok(testData);
        } catch (Exception e) {
            return ResponseEntity.internalServerError().build();
        }
    }
}

package org.springframework.samples.petclinic.api.boundary.web;

import org.springframework.samples.petclinic.api.dto.OwnerDetails;
import org.springframework.samples.petclinic.api.dto.PetDetails;
import org.springframework.samples.petclinic.api.dto.PetType;
import org.springframework.samples.petclinic.api.dto.VisitDetails;
import org.springframework.samples.petclinic.api.dto.Visits;
import org.springframework.stereotype.Component;

import java.util.List;
import org.springframework.samples.petclinic.api.dto.OwnerDetails.OwnerDetailsBuilder;
import org.springframework.samples.petclinic.api.dto.PetDetails.PetDetailsBuilder;

@Component
public class DtoAssembler {

    public OwnerDetails toOwnerDetails(int id, String firstName, String lastName,
                                      String address, String city, String telephone,
                                      List<PetDetails> pets) {
        return OwnerDetails.OwnerDetailsBuilder.anOwnerDetails()
                .id(id)
                .firstName(firstName)
                .lastName(lastName)
                .address(address)
                .city(city)
                .telephone(telephone)
                .pets(pets)
                .build();
    }

    public PetDetails toPetDetails(int id, String name, String birthDate,
                                  PetType type, List<VisitDetails> visits) {
        return PetDetails.PetDetailsBuilder.aPetDetails()
                .id(id)
                .name(name)
                .birthDate(birthDate)
                .type(type)
                .visits(visits)
                .build();
    }

    public PetType toPetType(String name) {
        return new PetType(name);
    }

    public VisitDetails toVisitDetails(Integer id, Integer petId, String date, String description) {
        return new VisitDetails(id, petId, date, description);
    }

    public Visits toVisits(List<VisitDetails> visits) {
        return new Visits(visits);
    }
}

