package org.springframework.samples.petclinic.api.application;

import org.springframework.samples.petclinic.api.dto.ArticleRequest;
import org.springframework.stereotype.Service;
import org.springframework.util.StringUtils;

import java.util.regex.Pattern;

@Service
public class ArticleValidationService {

    private static final Pattern SLUG_PATTERN = Pattern.compile("^[a-z0-9-]+$");

    public void validateArticle(ArticleRequest articleRequest) {
        validateSlug(articleRequest.slug());
    }

    private void validateSlug(String slug) {
        if (!StringUtils.hasText(slug)) {
            throw new IllegalArgumentException("Slug must not be empty");
        }
        if (slug.length() < 3 || slug.length() > 100) {
            throw new IllegalArgumentException("Slug must be between 3 and 100 characters long");
        }
        if (!SLUG_PATTERN.matcher(slug).matches()) {
            throw new IllegalArgumentException("Slug must contain only lowercase letters, numbers, and hyphens");
        }
    }
}

