package org.springframework.samples.petclinic.api.boundary.web;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.samples.petclinic.api.dto.ArticleRequest;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.server.ResponseStatusException;

@RestController
@RequestMapping("/api/articles")
public class ArticleController {

    private static final String SLUG_PATTERN = "^[a-z0-9-]{3,50}$";

    @PostMapping
    public ResponseEntity<String> createArticle(@RequestBody ArticleRequest request) {
        validateSlug(request.slug());
        return ResponseEntity.ok("Article created successfully");
    }

    @PutMapping
    public ResponseEntity<String> updateArticle(@RequestBody ArticleRequest request) {
        validateSlug(request.slug());
        return ResponseEntity.ok("Article updated successfully");
    }

    private void validateSlug(String slug) {
        if (slug == null || !slug.matches(SLUG_PATTERN)) {
            throw new ResponseStatusException(
                HttpStatus.BAD_REQUEST,
                "Slug must be 3-50 characters long and contain only lowercase letters, numbers, or hyphens"
            );
        }
    }
}

package org.springframework.samples.petclinic.genai;

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/chat")
public class SimpleChatController {

    @GetMapping
    public String chat(@RequestParam String message) {
        return processMessage(message);
    }

    private String processMessage(String message) {
        if (message == null || message.trim().isEmpty()) {
            return "Please provide a non-empty message.";
        }

        String lowerCaseMessage = message.toLowerCase();
        if (lowerCaseMessage.contains("hello") || lowerCaseMessage.contains("hi")) {
            return "Hello! How can I help you today?";
        } else if (lowerCaseMessage.contains("pet") || lowerCaseMessage.contains("animal")) {
            return "We love pets here! What would you like to know about your pet?";
        } else if (lowerCaseMessage.contains("vet") || lowerCaseMessage.contains("doctor")) {
            return "Our vets are ready to help. Would you like to schedule an appointment?";
        } else if (lowerCaseMessage.contains("help")) {
            return "Sure! I can help with pet care, vet appointments, and general questions about our clinic.";
        } else {
            return "Thanks for your message! How can we assist you further?";
        }
    }
}

