package org.springframework.samples.petclinic.customers.web;

import org.springframework.http.ResponseEntity;
import org.springframework.samples.petclinic.api.dto.OwnerDetails;
import org.springframework.samples.petclinic.api.dto.PetDetails;
import org.springframework.samples.petclinic.api.dto.PetType;
import org.springframework.samples.petclinic.customers.model.Owner;
import org.springframework.samples.petclinic.customers.model.OwnerRepository;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

@RestController
@RequestMapping("/api/profile")
public class ProfileResource {

    private final OwnerRepository ownerRepository;

    public ProfileResource(OwnerRepository ownerRepository) {
        this.ownerRepository = ownerRepository;
    }

    @GetMapping("/{ownerId}")
    public ResponseEntity<OwnerDetails> getProfile(@PathVariable int ownerId) {
        return ownerRepository.findById(ownerId)
                .map(owner -> {
                    List<PetDetails> pets = owner.getPets().stream()
                            .map(pet -> new PetDetails(
                                    pet.getId(),
                                    pet.getName(),
                                    pet.getBirthDate().toString(),
                                    new PetType(pet.getType().getName()),
                                    List.of()
                            ))
                            .collect(Collectors.toList());

                    OwnerDetails ownerDetails = new OwnerDetails(
                            owner.getId(),
                            owner.getFirstName(),
                            owner.getLastName(),
                            owner.getAddress(),
                            owner.getCity(),
                            owner.getTelephone(),
                            pets
                    );

                    return ResponseEntity.ok(ownerDetails);
                })
                .orElse(ResponseEntity.notFound().build());
    }
}

