package org.springframework.samples.petclinic.customers.web;

import org.springframework.http.HttpStatus;
import org.springframework.samples.petclinic.customers.model.Owner;
import org.springframework.samples.petclinic.customers.model.OwnerRepository;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/owners")
public class OwnerProfileResource {

    private final OwnerRepository ownerRepository;

    public OwnerProfileResource(OwnerRepository ownerRepository) {
        this.ownerRepository = ownerRepository;
    }

    @PutMapping("/{ownerId}")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void updateOwnerProfile(@PathVariable int ownerId, @RequestBody OwnerRequest ownerRequest) {
        Owner owner = ownerRepository.findById(ownerId)
            .orElseThrow(() -> new ResourceNotFoundException("Owner not found with id: " + ownerId));

        owner.setFirstName(ownerRequest.firstName());
        owner.setLastName(ownerRequest.lastName());
        owner.setAddress(ownerRequest.address());
        owner.setCity(ownerRequest.city());
        owner.setTelephone(ownerRequest.telephone());

        ownerRepository.save(owner);
    }
}

