import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/owners")
public class OwnerProfileController {

    private final OwnerRepository ownerRepository;

    public OwnerProfileController(OwnerRepository ownerRepository) {
        this.ownerRepository = ownerRepository;
    }

    @PutMapping("/{ownerId}")
    public Owner updateOwnerProfile(@PathVariable int ownerId, @RequestBody OwnerRequest ownerRequest) {
        return ownerRepository.findById(ownerId)
            .map(existingOwner -> {
                existingOwner.setFirstName(ownerRequest.firstName());
                existingOwner.setLastName(ownerRequest.lastName());
                existingOwner.setAddress(ownerRequest.address());
                existingOwner.setCity(ownerRequest.city());
                existingOwner.setTelephone(ownerRequest.telephone());
