            .orElseThrow(() -> new ResourceNotFoundException("Owner not found with id: " + ownerId));
    }
}

package org.springframework.samples.petclinic.genai;

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/genai/simple-chat")
public class SimpleChatController {

    @GetMapping
    public String chat(@RequestParam String message) {
        return processMessage(message);
    }

    private String processMessage(String message) {
        if (message == null || message.trim().isEmpty()) {
            return "Hello! How can I help you with your pet today?";
        }

        String lowerCaseMessage = message.toLowerCase();
        if (lowerCaseMessage.contains("hello") || lowerCaseMessage.contains("hi")) {
            return "Hello! How can I assist you with your pet?";
        } else if (lowerCaseMessage.contains("help")) {
            return "I can help with pet care tips, vet recommendations, or general pet health questions. What do you need?";
        } else if (lowerCaseMessage.contains("vet") || lowerCaseMessage.contains("doctor")) {
            return "For vet-related questions, please visit our vets section or contact a specialist directly.";
        } else if (lowerCaseMessage.contains("pet") || lowerCaseMessage.contains("animal")) {
            return "Pets are wonderful companions! What would you like to know about pet care?";
        } else {
            return "I'm here to help with pet-related questions. Try asking about vets, pet care, or general pet health!";
        }
    }
}

package org.springframework.samples.petclinic.genai;

import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/genai/simple-chat")
public class SimpleChatController {

    @PostMapping
    public String handleSimpleChat(@RequestBody String prompt) {
        return generateSimpleResponse(prompt);
    }

    private String generateSimpleResponse(String prompt) {
        if (prompt == null || prompt.trim().isEmpty()) {
            return "Please provide a valid prompt.";
        }

        String lowerPrompt = prompt.toLowerCase();
        if (lowerPrompt.contains("hello") || lowerPrompt.contains("hi")) {
            return "Hello! How can I assist you today?";
        } else if (lowerPrompt.contains("help")) {
            return "Sure! What do you need help with?";
        } else if (lowerPrompt.contains("pet") || lowerPrompt.contains("animal")) {
            return "I can provide information about pets. What would you like to know?";
        } else {
            return "Thank you for your message. I'm a simple chatbot and can only respond to basic queries.";
        }
    }
}

package org.springframework.samples.petclinic.genai;

import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class SimpleChatController {

    @PostMapping("/api/genai/simple-chat")
    public String handleChat(@RequestBody String prompt) {
        if (prompt == null || prompt.trim().isEmpty()) {
            return "Please provide a valid prompt.";
        }

        String response;
        String lowerPrompt = prompt.toLowerCase();

        if (lowerPrompt.contains("hello") || lowerPrompt.contains("hi")) {
            response = "Hello! How can I help you with your pet today?";
        } else if (lowerPrompt.contains("pet") && lowerPrompt.contains("care")) {
            response = "For general pet care, ensure regular vet visits, a balanced diet, and plenty of exercise.";
        } else if (lowerPrompt.contains("vet") && lowerPrompt.contains("appointment")) {
            response = "You can schedule a vet appointment through our PetClinic portal or by calling your local clinic.";
        } else if (lowerPrompt.contains("thank") || lowerPrompt.contains("thanks")) {
            response = "You're welcome! Feel free to ask if you have more questions.";
        } else {
            response = "I'm a simple pet clinic assistant. Try asking about pet care or vet appointments!";
        }

        return response;
    }
}

