        public ArticleDetailsBuilder id(Integer id) {
            this.id = id;
            return this;
        }

        public ArticleDetailsBuilder title(String title) {
            this.title = title;
            return this;
        }

        public ArticleDetailsBuilder content(String content) {
            this.content = content;
            return this;
        }

        public ArticleDetailsBuilder author(String author) {
            this.author = author;
            return this;
        }

        public ArticleDetailsBuilder publicationDate(String publicationDate) {
            this.publicationDate = publicationDate;
            return this;
        }

        public ArticleDetails build() {
            return new ArticleDetails(id, title, content, author, publicationDate);
        }
    }
}

