import reactor.core.publisher.Mono;

@RestController
@RequestMapping("/api/articles")
public class ArticleController {

    @GetMapping
    public Flux<ArticleDetails> getAllArticles() {
        return Flux.empty();
    }

    @GetMapping("/{id}")
    public Mono<ArticleDetails> getArticleById(@PathVariable Integer id) {
        return Mono.empty();
    }

    @PostMapping
    public Mono<ArticleDetails> createArticle(@RequestBody ArticleDetails articleDetails) {
        return Mono.just(articleDetails);
    }

    @PutMapping("/{id}")
    public Mono<ArticleDetails> updateArticle(
        @PathVariable Integer id,
        @RequestBody ArticleDetails articleDetails
    ) {
        return Mono.just(articleDetails);
    }
}

package org.springframework.samples.petclinic.api.boundary.web;

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.samples.petclinic.api.dto.ArticleDetails;

import java.util.List;

@RestController
@RequestMapping("/api/articles")
public class ArticleController {

    @GetMapping
    public List<ArticleDetails> getAllArticles() {
        return List.of();
    }

    @GetMapping("/{id}")
    public ArticleDetails getArticle(@PathVariable int id) {
        return new ArticleDetails(id, "Sample Title", "Sample Content", "Sample Author");
    }

    @PostMapping
    public ArticleDetails createArticle(@RequestBody ArticleDetails articleDetails) {
        return articleDetails;
    }

    @PutMapping("/{id}")
    public ArticleDetails updateArticle(@PathVariable int id, @RequestBody ArticleDetails articleDetails) {
        return articleDetails;
    }
}

package org.springframework.samples.petclinic.api.dto;

public record ArticleDetails(
    int id,
    String title,
    String content,
    String author
) {}

package org.springframework.samples.petclinic.api.dto;

public record ArticleDto(
    Integer id,
    String title,
    String content,
    String author
) {}

package org.springframework.samples.petclinic.api.application;

import org.springframework.samples.petclinic.api.dto.ArticleDto;
import java.util.List;

public interface ArticleService {
    ArticleDto getArticleById(Integer id);
    List<ArticleDto> getAllArticles();
}

package org.springframework.samples.petclinic.api.boundary.web;

import org.springframework.samples.petclinic.api.application.ArticleService;
import org.springframework.samples.petclinic.api.dto.ArticleDto;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import java.util.List;

@RestController
@RequestMapping("/api/articles")
public class ArticleRestController {

    private final ArticleService articleService;

    public ArticleRestController(ArticleService articleService) {
        this.articleService = articleService;
    }

    @GetMapping("/{id}")
    public ArticleDto getArticle(@PathVariable Integer id) {
        return articleService.getArticleById(id);
    }

    @GetMapping
    public List<ArticleDto> getAllArticles() {
        return articleService.getAllArticles();
    }
}

